#include <stdio.h>
#include <stdlib.h>

// Define the structure for a node in the linked list
typedef struct Node {
    int key;
    int value;
    int frequency;
    struct Node* next;
    struct Node* prev;
} Node;

// Define the structure for the LFU cache
typedef struct LFUCache {
    int capacity;
    int size;
    Node** cache;
} LFUCache;

// Function to create a new node
Node* createNode(int key, int value) {
    Node* node = (Node*) malloc(sizeof(Node));
    node->key = key;
    node->value = value;
    node->frequency = 1;
    node->next = NULL;
    node->prev = NULL;
    return node;
}

// Function to initialize the LFU cache
LFUCache* lfuCacheCreate(int capacity) {
    LFUCache* cache = (LFUCache*) malloc(sizeof(LFUCache));
    cache->capacity = capacity;
    cache->size = 0;
    cache->cache = (Node**) malloc(sizeof(Node*) * capacity);
    return cache;
}

// Function to get the value of a key from the LFU cache
int lfuCacheGet(LFUCache* obj, int key) {
    // Check if the key exists in the cache
    for (int i = 0; i < obj->size; i++) {
        if (obj->cache[i]->key == key) {
            // Update the frequency of the node
            obj->cache[i]->frequency++;
            return obj->cache[i]->value;
        }
    }
    // If the key does not exist, return -1
    return -1;
}

// Function to put a key-value pair into the LFU cache
void lfuCachePut(LFUCache* obj, int key, int value) {
    // Check if the key already exists in the cache
    for (int i = 0; i < obj->size; i++) {
        if (obj->cache[i]->key == key) {
            // Update the value and frequency of the node
            obj->cache[i]->value = value;
            obj->cache[i]->frequency++;
            return;
        }
    }
    // If the key does not exist, add a new node to the cache
    if (obj->size < obj->capacity) {
        Node* node = createNode(key, value);
        obj->cache[obj->size] = node;
        obj->size++;
    } else {
        // If the cache is full, remove the least frequently used node
        int minFrequency = INT_MAX;
        int index = -1;
        for (int i = 0; i < obj->size; i++) {
            if (obj->cache[i]->frequency < minFrequency) {
                minFrequency = obj->cache[i]->frequency;
                index = i;
            }
        }
        // Remove the least frequently used node
        free(obj->cache[index]);
        obj->cache[index] = createNode(key, value);
    }
}

