using namespace std;

class Node {
public:
    int key, value, frequency;
    Node(int k, int v) : key(k), value(v), frequency(1) {}
};

class LFUCache {
private:
    int capacity;
    unordered_map<int, Node*> cache;
    unordered_map<int, list<Node*>> frequencyMap;
    int minFrequency;

public:
    LFUCache(int cap) : capacity(cap), minFrequency(0) {}

    int get(int key) {
        if (cache.find(key) != cache.end()) {
            Node* node = cache[key];
            frequencyMap[node->frequency].remove(node);
            if (frequencyMap[node->frequency].empty()) {
                frequencyMap.erase(node->frequency);
                if (minFrequency == node->frequency) {
                    minFrequency++;
                }
            }
            node->frequency++;
            frequencyMap[node->frequency].push_back(node);
            return node->value;
        }
        return -1;
    }

    void put(int key, int value) {
        if (capacity == 0) return;
        if (cache.find(key) != cache.end()) {
            Node* node = cache[key];
            node->value = value;
            frequencyMap[node->frequency].remove(node);
            if (frequencyMap[node->frequency].empty()) {
                frequencyMap.erase(node->frequency);
                if (minFrequency == node->frequency) {
                    minFrequency++;
                }
            }
            node->frequency++;
            frequencyMap[node->frequency].push_back(node);
        } else {
            if (cache.size() == capacity) {
                Node* node = frequencyMap[minFrequency].front();
                cache.erase(node->key);
                frequencyMap[minFrequency].pop_front();
                if (frequencyMap[minFrequency].empty()) {
                    frequencyMap.erase(minFrequency);
                }
            }
            Node* newNode = new Node(key, value);
            cache[key] = newNode;
            frequencyMap[1].push_back(newNode);
            minFrequency = 1;
        }
    }
};

