import java.util.HashMap;
import java.util.Map;
import java.util.LinkedHashSet;
import java.util.Set;

public class LFUCache {
    private Map<Integer, Node> cache;
    private Map<Integer, Set<Node>> frequencyMap;
    private int capacity;
    private int minFrequency;

    public LFUCache(int capacity) {
        this.capacity = capacity;
        this.cache = new HashMap<>();
        this.frequencyMap = new HashMap<>();
        this.minFrequency = 0;
    }

    public int get(int key) {
        if (cache.containsKey(key)) {
            Node node = cache.get(key);
            frequencyMap.get(node.frequency).remove(node);
            if (frequencyMap.get(node.frequency).isEmpty()) {
                frequencyMap.remove(node.frequency);
                if (minFrequency == node.frequency) {
                    minFrequency++;
                }
            }
            node.frequency++;
            frequencyMap.computeIfAbsent(node.frequency, k -> new LinkedHashSet<>()).add(node);
            return node.value;
        }
        return -1;
    }

    public void put(int key, int value) {
        if (capacity == 0) return;
        if (cache.containsKey(key)) {
            Node node = cache.get(key);
            node.value = value;
            frequencyMap.get(node.frequency).remove(node);
            if (frequencyMap.get(node.frequency).isEmpty()) {
                frequencyMap.remove(node.frequency);
                if (minFrequency == node.frequency) {
                    minFrequency++;
                }
            }
            node.frequency++;
            frequencyMap.computeIfAbsent(node.frequency, k -> new LinkedHashSet<>()).add(node);
        } else {
            if (cache.size() == capacity) {
                Node node = frequencyMap.get(minFrequency).iterator().next();
                cache.remove(node.key);
                frequencyMap.get(minFrequency).remove(node);
                if (frequencyMap.get(minFrequency).isEmpty()) {
                    frequencyMap.remove(minFrequency);
                }
            }
            Node newNode = new Node(key, value);
            cache.put(key, newNode);
            frequencyMap.computeIfAbsent(1, k -> new LinkedHashSet<>()).add(newNode);
            minFrequency = 1;
        }
    }

    private class Node {
        int key;
        int value;
        int frequency;

        public Node(int key, int value) {
            this.key = key;
            this.value = value;
        }
    }
}

